package tar_01;

public class Carro {
	public String marca;
	public String modelo;
	public String anoFabricacao;
	
	@Override
	public String toString() {
		// TODO Auto-generated method stub
		return "Marca: " + marca +
				"\nModelo: " + modelo +
				"\nAno de fabricação: " + anoFabricacao + "\n";
	}
}
